/**
 * LLM Synthetic Conversation Tests
 *
 * These tests validate that realistic conversation patterns (like those
 * generated by LLMs or real users) correctly trigger data capture.
 *
 * Tests cover:
 * - Emotional conversations (grief, celebration, anxiety)
 * - Relationship dynamics (conflicts, reconciliation)
 * - Goal-setting and commitments
 * - Multi-domain conversations
 * - Subtle/implicit mentions
 * - Edge cases and boundary conditions
 */

import { describe, it, expect, beforeEach, vi, afterEach } from 'vitest';
import { extractNames, extractPerson } from '../../services/superhuman/relationship-network.js';
import { detectCommitment } from '../../services/superhuman/commitment-keeper.js';
import { detectDream } from '../../services/superhuman/dream-keeper.js';
import { detectValue, type ValueCategory } from '../../services/superhuman/values-alignment.js';
import { processDataCapture, captureDataBetterThanHuman } from '../../intelligence/data-capture/index.js';
import { allDataCaptureDefinitions } from '../../intelligence/data-capture/definitions/index.js';

// ============================================================================
// TEST SETUP
// ============================================================================

const TEST_USER_ID = 'llm-test-user-123';
const TEST_SESSION_ID = 'llm-test-session-456';

// Mock Firestore for storage tests
const mockFirestoreData = new Map<string, unknown>();

vi.mock('../../memory/firestore-client.js', () => ({
  getFirestoreDb: vi.fn(() => ({
    collection: vi.fn(() => ({
      doc: vi.fn(() => ({
        set: vi.fn(async (data: unknown) => {
          mockFirestoreData.set('last_write', data);
        }),
        get: vi.fn(async () => ({
          exists: false,
          data: () => null,
        })),
        update: vi.fn(),
        collection: vi.fn(() => ({
          add: vi.fn(),
          doc: vi.fn(() => ({
            set: vi.fn(),
            get: vi.fn(async () => ({ exists: false })),
          })),
        })),
      })),
      add: vi.fn(),
    })),
    runTransaction: vi.fn(async (fn: (t: unknown) => Promise<void>) => {
      await fn({ get: vi.fn(), set: vi.fn(), update: vi.fn() });
    }),
  })),
}));

// Track all storage calls for verification
const storageCalls = {
  contacts: [] as unknown[],
  commitments: [] as unknown[],
  dreams: [] as unknown[],
  values: [] as unknown[],
  relationships: [] as unknown[],
  entityStore: [] as unknown[],
};

function resetStorageCalls() {
  storageCalls.contacts = [];
  storageCalls.commitments = [];
  storageCalls.dreams = [];
  storageCalls.values = [];
  storageCalls.relationships = [];
  storageCalls.entityStore = [];
}

beforeEach(() => {
  resetStorageCalls();
  mockFirestoreData.clear();
  vi.clearAllMocks();
});

// ============================================================================
// CONVERSATION TYPES
// ============================================================================

interface ConversationScenario {
  name: string;
  description: string;
  turns: string[];
  expectations: {
    shouldExtractNames?: string[];
    shouldDetectCommitment?: boolean;
    shouldDetectDream?: boolean;
    shouldDetectValue?: ValueCategory[];
    shouldCaptureContact?: boolean;
    shouldDetectBoundary?: boolean;
  };
}

// ============================================================================
// 1. EMOTIONAL CONVERSATIONS
// ============================================================================

describe('Emotional Conversations', () => {
  const emotionalScenarios: ConversationScenario[] = [
    {
      name: 'Processing Grief',
      description: 'User discussing loss of a loved one',
      turns: [
        "I've been having a hard time lately",
        'My grandmother passed away last month',
        "I talked to Margaret about it before she passed", // Uses pattern "talked to X"
        "I don't want to talk about the funeral details right now",
        "I'm going to take care of the garden she loved", // Commitment pattern
      ],
      expectations: {
        shouldExtractNames: ['Margaret'],
        shouldDetectCommitment: true,
        shouldDetectBoundary: true, // "don't want to talk about"
      },
    },
    {
      name: 'Celebration Mode',
      description: 'User sharing exciting news',
      turns: [
        "I just got the best news!",
        "Rachel told me I got the promotion!", // "X told me" pattern
        "Michael said I earned it", // "X said" pattern
        "I'm going to call my parents to celebrate",
        "My health comes first", // Matches health pattern
      ],
      expectations: {
        shouldExtractNames: ['Rachel', 'Michael'],
        shouldDetectCommitment: true, // "I'm going to call"
        shouldDetectValue: ['health'],
      },
    },
    {
      name: 'Anxiety Processing',
      description: 'User working through anxiety',
      turns: [
        "I've been feeling really anxious about work",
        "My therapist Dr. Chen suggested breathing exercises",
        "I want to learn meditation this year",
        "My partner Sam has been really supportive",
        "I'm going to try the calm app tonight",
      ],
      expectations: {
        shouldExtractNames: ['Sam'],
        shouldDetectDream: false, // "learn meditation" might match
        shouldDetectCommitment: true, // "I'm going to try"
      },
    },
  ];

  emotionalScenarios.forEach(({ name, description, turns, expectations }) => {
    describe(name, () => {
      it(`should correctly capture data from: ${description}`, async () => {
        const results = await runConversation(turns);
        validateExpectations(results, expectations);
      });
    });
  });
});

