// ============================================================================
// 5. EDGE CASES
// ============================================================================

describe('Edge Cases', () => {
  it('should handle empty turns gracefully', async () => {
    const results = await runConversation(['', '   ', '\n']);
    expect(results.allNames).toEqual([]);
    expect(results.foundCommitment).toBe(false);
  });

  it('should handle very long turns without crashing', async () => {
    const longTurn = 'I talked to Sarah about ' + 'many things '.repeat(500);
    const results = await runConversation([longTurn]);
    expect(results).toBeDefined();
    expect(results.allNames).toContain('Sarah');
  });

  it('should not extract common words as names', async () => {
    const results = await runConversation([
      'The Monday meeting was great',
      'I really enjoyed the Tuesday session',
      'Looking forward to next week',
    ]);
    // Should not extract "Monday", "Tuesday", etc as names
    const lowerNames = results.allNames.map(n => n.toLowerCase());
    expect(lowerNames).not.toContain('monday');
    expect(lowerNames).not.toContain('tuesday');
    expect(lowerNames).not.toContain('looking');
  });

  it('should handle mixed case properly', async () => {
    const results = await runConversation([
      'MY FRIEND SARAH told me something',
      'I talked to bob yesterday',
    ]);
    // Should extract SARAH as Sarah, bob as Bob (if capitalized in context)
    expect(results.allNames.some(n => n.toLowerCase() === 'sarah')).toBe(true);
  });

  it('should not falsely detect commitments from questions', async () => {
    const results = await runConversation([
      'Will I ever finish this project?',
      'Should I call my mom?',
      'What if I start exercising tomorrow?',
    ]);
    // Questions shouldn't be detected as commitments
    expect(results.foundCommitment).toBe(false);
  });

  it('should handle unicode and special characters', async () => {
    const results = await runConversation([
      'My friend José told me about the café',
      "Müller mentioned it's great",
      "I'll meet Jean-Pierre there",
    ]);
    // Should handle gracefully without crashing
    expect(results).toBeDefined();
  });
});

// ============================================================================
// 6. MULTI-DOMAIN CONVERSATIONS (COMPREHENSIVE)
// ============================================================================

describe('Multi-Domain Comprehensive', () => {
  it('should capture multiple domains in a single realistic conversation', async () => {
    const comprehensiveConversation = [
      // Session start
      "Hey, it's been a crazy week",

      // Family domain
      "My mom Betty's number is 555-123-4567", // "My mom X" extraction pattern
      "Tom mentioned reaching out more", // "X mentioned" extraction pattern

      // Work domain
      "Sarah told me about a promotion opportunity", // "X told me" pattern
      "I talked to David about it", // "talked to X" pattern

      // Goals/Dreams
      "I want to start my own business someday", // Exact dream pattern match
      "I'm going to update my resume this weekend",

      // Values
      "Family is everything to me", // Family value pattern
      "I want to achieve great things", // Achievement pattern

      // Boundaries
      "I don't want to talk about my salary though", // Boundary phrase

      // Health
      "My health comes first", // Health value pattern
      "I'm going to go to the gym three times a week", // Commitment pattern
    ];

    const results = await runConversation(comprehensiveConversation);

    // Should extract all mentioned people
    expect(results.allNames).toContain('Betty');
    expect(results.allNames).toContain('Tom');
    expect(results.allNames).toContain('Sarah');
    expect(results.allNames).toContain('David');

    // Should detect contact (mom's phone number)
    expect(results.contactsCaptured).toBe(true);

    // Should detect dream (start own business)
    expect(results.foundDream).toBe(true);

    // Should detect commitments (update resume, gym)
    expect(results.foundCommitment).toBe(true);

    // Should detect values (family, health)
    expect(results.foundValues.length).toBeGreaterThan(0);
    expect(results.foundValues).toContain('family');
    expect(results.foundValues).toContain('health');

    // Should detect boundary
    expect(results.foundBoundary).toBe(true);
  });
});

