// ============================================================================
// TEST UTILITIES
// ============================================================================

interface ConversationResults {
  allNames: string[];
  foundCommitment: boolean;
  foundDream: boolean;
  foundValues: ValueCategory[];
  contactsCaptured: boolean;
  foundBoundary: boolean;
  turnsProcessed: number;
}

async function runConversation(turns: string[]): Promise<ConversationResults> {
  const allNames: string[] = [];
  let foundCommitment = false;
  let foundDream = false;
  const foundValues: ValueCategory[] = [];
  let contactsCaptured = false;
  let foundBoundary = false;

  for (const turn of turns) {
    if (!turn || !turn.trim()) continue;

    // PATH 1: Name extraction
    const extracted = extractNames(turn);
    allNames.push(...extracted.map(e => e.name));

    // PATH 2: Data capture
    const captureResult = await processDataCapture({
      userId: TEST_USER_ID,
      sessionId: TEST_SESSION_ID,
      transcript: turn,
    });

    if (captureResult.captured.some(c => c.entity.type === 'contact')) {
      contactsCaptured = true;
    }

    // Detection tests
    const commitment = detectCommitment(turn, TEST_USER_ID);
    if (commitment.detected) foundCommitment = true;

    const dream = detectDream(turn);
    if (dream) foundDream = true;

    const value = detectValue(turn);
    if (value) {
      if (!foundValues.includes(value.category)) {
        foundValues.push(value.category);
      }
    }

    // Check for boundary phrases
    const boundaryDef = allDataCaptureDefinitions.find(d => d.id === 'capture_boundary');
    if (boundaryDef) {
      const lowerTurn = turn.toLowerCase();
      const hasPhrase = boundaryDef.triggers.phrases?.some(p => lowerTurn.includes(p.toLowerCase()));
      const hasPattern = boundaryDef.triggers.patterns?.some(p => p.test(turn));
      if (hasPhrase || hasPattern) {
        foundBoundary = true;
      }
    }
  }

  return {
    allNames: [...new Set(allNames)], // Dedupe
    foundCommitment,
    foundDream,
    foundValues,
    contactsCaptured,
    foundBoundary,
    turnsProcessed: turns.filter(t => t && t.trim()).length,
  };
}

function validateExpectations(
  results: ConversationResults,
  expectations: ConversationScenario['expectations']
) {
  if (expectations.shouldExtractNames) {
    expectations.shouldExtractNames.forEach(name => {
      const found = results.allNames.some(
        n => n.toLowerCase() === name.toLowerCase()
      );
      expect(found).toBe(true);
    });
  }

  if (expectations.shouldDetectCommitment !== undefined) {
    expect(results.foundCommitment).toBe(expectations.shouldDetectCommitment);
  }

  if (expectations.shouldDetectDream !== undefined) {
    expect(results.foundDream).toBe(expectations.shouldDetectDream);
  }

  if (expectations.shouldDetectValue) {
    expectations.shouldDetectValue.forEach(value => {
      expect(results.foundValues).toContain(value);
    });
  }

  if (expectations.shouldCaptureContact !== undefined) {
    expect(results.contactsCaptured).toBe(expectations.shouldCaptureContact);
  }

  if (expectations.shouldDetectBoundary !== undefined) {
    expect(results.foundBoundary).toBe(expectations.shouldDetectBoundary);
  }
}

